+class MatchEachExpression {
+  constructor(private steps: Step[], private hasInput: boolean, private input: unknown) {}
+
+  with(...args: any[]) {
+    const handler = args[args.length - 1];
+    const patterns = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return this.next({ patterns, predicate, handler });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return this.next({ patterns: [], predicate, handler: (_selection, value) => handler(value) });
+  }
+
+  tap(callback: (result: unknown) => void) { return this.next({ tap: callback }); }
+  returnType() { return this; }
+  narrow() { return this; }
+
+  otherwise(handler: (value: unknown) => unknown) {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+  exhaustive(handler = defaultCatcher) {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+  run() { return this.exhaustive(); }
